import { SelfReflectionEngine } from './src/self_reflection.js';

async function main() {
  const engine = new SelfReflectionEngine('./history');
  const sessions = await engine.loadSessions();
  const insights = await engine.reflect();

  console.log('╔════════════════════════════════════════════════════════╗');
  console.log('║  SR ANALYSIS | Current State                           ║');
  console.log('╚════════════════════════════════════════════════════════╝');
  console.log();
  console.log(`Sessions: ${sessions.length}`);
  console.log(`Insights Generated: ${insights.length}`);
  console.log();

  // Tool breakdown
  const toolMap = new Map<string, number>();
  let total = 0;
  for (const s of sessions) {
    for (const tc of s.toolCalls) {
      toolMap.set(tc.tool, (toolMap.get(tc.tool) || 0) + tc.count);
      total += tc.count;
    }
  }

  console.log('TOOL USAGE:');
  const sorted = Array.from(toolMap.entries()).sort((a, b) => b[1] - a[1]);
  sorted.slice(0, 6).forEach(([tool, count]) => {
    const bar = '█'.repeat(Math.round((count / total) * 20));
    console.log(`  ${tool.padEnd(20)} ${bar} ${count}`);
  });

  console.log();
  console.log('INSIGHTS:');
  insights.forEach(i => {
    const emoji = {progress: '📈', habit: '🔁', pattern: '🔄', anomaly: '⚠️'}[i.type] || '•';
    console.log(`  ${emoji} ${i.type}: ${i.description.slice(0, 50)}...`);
  });
}

main();
